INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('disabled-c5fb3965-moex-00091', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-34c7f7f6', 'sub-disabled-c5fb3965-03', NULL, 'single_choice', '「大多數侍酒師其實天生嗅覺和味覺都沒有那麼敏銳，不適用於卡拉漢的 『嗅覺直覺』策略。為了要通過侍酒大師考試的『品酒』測試，他們通常 從『暴力破解法』開始：盡量增加品嚐的酒類，提高品嚐的頻率，藉由反 覆接觸讓頭腦把酒和味道配對在一起。……相較之下，蕾佩樂媞是以哲學 的策略準備，她說：『我很愛思索「為什麼」，所以酒滿足了我的好奇心。 某款酒的味道「為什麼」是這樣，背後一定有原因，我會以哲學的推論方 法找出來。』」 根據上文，下列選項何者不是成為侍酒師的方法？', '["熟能生巧", "順性而為", "反覆練習", "追根究柢"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00092', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-34c7f7f6', 'sub-disabled-c5fb3965-03', NULL, 'single_choice', '「柯靈烏認為歷史學家必須用審慎的眼光檢視過去，即使這表示要揭露一 些大家珍視已久的迷思。他說：『若歷史和現在毫無關係，那麼過去的歷 史知識對現在就沒什麼幫助。但假設歷史一路影響到現在，那麼即使是塵 封在內部，或乍看之下隱藏於當前矛盾的外表下，這歷史仍然是鮮活且有 影響力的。』」 根據上文，下列選項何者最符合文意？', '["真相始終潛藏在矛盾中，所以歷史仍能鮮活且有影響力", "無論是否對現今社會產生意義，歷史都有其研究的價值", "歷史研究的目的，在於不斷提出新事證以推翻過往定論", "歷史學家不應被既有的迷思所框限，而能致力發掘真相"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00093', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-34c7f7f6', 'sub-disabled-c5fb3965-03', NULL, 'single_choice', '「精緻藝文既能超越時空，『普及化』自能更顯其真價，真正令人憂慮的 是『庸俗化』——無須等到文化創意產業發展法（下稱文創法）施行。許 多新聞只知追求自以為是的爆點，內容卻乏善可陳。多少音樂家活到老學 到老，同一首作品縱使演奏數十年，仍能日新又新，永遠有新發現。但無 論他們在記者會多麼無私分享千錘百鍊後的心得，媒體卻往往只挑那些最 膚淺、和主題最無關、讀後無法增進任何益處的內容來刊登。」 根據上文，下列選項最符合文意的是：', '["文創法的實行會加劇藝文的庸俗化", "新聞曝光度與提升藝文鑑賞力不可一概而論", "媒體的藝文報導滿足了絕大多數民眾的期望", "藝術家不應為了票房而提供與主題無關的訊息"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00094', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-34c7f7f6', 'sub-disabled-c5fb3965-03', NULL, 'single_choice', '「史丹福大學心理學家杜維克教授提出，『成見的威脅』是一種讓意志力 減弱的心態，研究中發現，讀了『記憶力隨年齡上升而減弱』文章的人， 和沒有讀過這篇文章的人相較之下，讀過文章的人實際上能記住的單字量 較少。換句話說，『記憶力隨著年紀變大而退化』深植腦中後，人確實會 被這樣的成見影響。」 根據上文，下列選項最符合文意的是：', '["年齡確實是決定意志力強弱的關鍵", "記憶力會隨著年齡增長而不斷退化", "年齡愈長，所累積的成見也會愈多", "成見會減弱人的意志力，無關年齡"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00095', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-34c7f7f6', 'sub-disabled-c5fb3965-03', NULL, 'single_choice', '尼采說：「無論是相愛時、爭執時，還是相互尊敬時，其中一方總是得承 擔各種麻煩事。這些人的共通點，就是個性急躁。個性急躁的人面對任何 情況，總會在事情尚未結束前，就急著反應，做出多餘的言行，導致感情 破裂。所以不管再怎麼簡單平常的事，都會被他們搞成麻煩事。」 根據上文，下列選項最符合文意的是：', '["要懂得放慢生活腳步，才能應付急躁的人", "急躁會為人帶來麻煩，更會影響人際關係", "與人相處要不怕麻煩，才能遠離急躁的人", "急躁的人就是怕麻煩，卻成了別人的麻煩"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00096', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-34c7f7f6', 'sub-disabled-c5fb3965-03', NULL, 'single_choice', '「一般人提到高齡、老年，通常是負面的評價居多，但是米開朗基羅在八 十八歲時才完成了著名的穹頂設計和圓頂底座建築設計；野獸派畫家馬諦 斯晚年時因為無法站立，必須一直坐在輪椅上，結果竟讓他發明了全新的 剪紙拼貼創作，可見即使人生進入下半場、甚至高齡階段之後，也應該還 是有機會開創新猷。」 根據上文，下列選項何者最符合文意？', '["廉頗老矣，尚能飯否", "家有一老，如有一寶", "莫道桑榆晚，為霞尚滿天", "少壯不努力，老大徒傷悲"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00097', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-34c7f7f6', 'sub-disabled-c5fb3965-03', NULL, 'single_choice', '「懶惰的耳朵聽到的，通常是一首歌裡的歌詞，歌詞附隨音高變化的旋律。 碰到沒有歌詞的音樂，懶惰的耳朵就有點不知所措了，缺乏歌詞指引就不 太找得到旋律，就算找到了一不小心就跟丟了。這樣的耳朵，不可能聽巴 哈。巴哈的音樂都是用對位法寫的，幾乎隨時都有超過一個旋律在進行， 兩個、三個、甚至更多旋律上下飄飛，而且彼此之間透過時間程序，構成 井然的秩序。更神奇的，不同聲部聲音一起出現時，又結合為和諧的和聲， 如此不斷變化。沒有誰的耳朵真的不能、不夠拿來聽巴哈，祇是耳朵要勤 勞、要充分使用，才能聽見巴哈。所以倒過來看，也就是，認真用心地聽 巴哈，就能讓我們的耳朵拾回那些被廢棄阻塞了的能力，還我們完整的聽 力。」 根據上文，下列選項何者最不符合文意？', '["巴哈音樂能提升感知能力", "文化藝術能讓人耳聰神清", "充耳不聞將使人感官退化", "和諧旋律可端正世俗視聽"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00098', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-34c7f7f6', 'sub-disabled-c5fb3965-03', NULL, 'single_choice', '「當我們聘用一位公務員，其實並不可能將技術與生命分割，一個人一定 是一個整體的存在，除了技術，他的心靈態度自然會對於技術的應用、目 的加以反省，進而進行一種全人的、人性的判斷。我們並不是要聘用機器， 而是要聘用一個活潑潑的生命，這裡除了技術知識之外，當然也應該盡可 能重視個人的人格特質、服務精神、表達能力與理想堅持。這樣的要求或 許並不容易完成，在操作上也有一定的難度，但是這樣的目標與理想，依 然值得我們的肯定與堅持。」 根據上文，下列選項最符合文意的是：', '["沒有任何職場上的人力與工作，是可以被人工智慧所取代", "在職場上我們不只是在做事而已，同時更要積極學習做人", "人才培育應該強調儘早地進行科目專精，並且專業化分流", "聘用一個人的雙手勤懇做事，勝過於這人擁有獨特的想法"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00099', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-34c7f7f6', 'sub-disabled-c5fb3965-03', NULL, 'single_choice', '「服裝產業是世界上第二大汙染產業，僅次於石油業。這項事實肯定令很 多人感到驚訝。一般我們談到汙染，大部分會聯想到石化、燃油、重工業， 但整個服裝產業會牽涉到的供應鏈，其實是相當廣泛且嚴重的。時尚是一 個複雜的業務，它涉及生產、原料，紡織品製造、服裝設計，運輸、零售 等環節，包含長期且多樣的供應鏈，時尚的碳足跡是非常巨大的。」 根據上文，下列選項何者正確？', '["用在地原料製衣，能達到產業淨零碳排", "時尚產業是僅次於石化產業的環境殺手", "服裝產業將為社會提供許多的就業機會", "時尚產業的永續目標是延長服裝的壽命"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00100', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-34c7f7f6', 'sub-disabled-c5fb3965-03', NULL, 'single_choice', '「影響購買意願的形象，也經常根據每個顧客區間而不同，因此不要把忠 誠、一般、流失和有認知但未購買混合在一起進行形象評價，應該分開對 每個區間進行相關分析。以購買意願而言，比較能引發顧客購買的應該是 『產品創意』的效益，和具獨特性的商品功能，兩者形象之間有很強的相 關性。」 根據上文，下列選項何者正確？', '["品牌忠誠度是顧客購買與否的唯一關鍵", "顧客的購買意願為一普遍的數字可量測", "產品創意與商品功能兩者具有因果關係", "若想了解顧客購買意願應進行區間分析"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL)
